import librosa
y, sr = librosa.load('/workspace/input.wav', sr=None)
for delta in [0.05, 0.1, 0.15, 0.2, 0.25]:
    for wait in [10, 15, 20, 25, 30]:
        for pre_max in [3, 5, 10]:
            for post_max in [3, 5, 10]:
                onsets = librosa.onset.onset_detect(y=y, sr=sr, backtrack=True, delta=delta, wait=wait, pre_max=pre_max, post_max=post_max)
                onset_times = librosa.frames_to_time(onsets, sr=sr)
                if len(onset_times) == 5 and abs(onset_times[0] - 0.046) < 0.05 and abs(onset_times[-1] - 4.78) < 0.1:
                    print(f'delta={delta}, wait={wait}, pre_max={pre_max}, post_max={post_max}: {onset_times}')
"
